import{_ as t,c as i,o as s,a1 as e}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"DM 配對與存取控制：保護你的 AI 助手 | Clawdbot 教程","description":"了解 Clawdbot 的 DM 配對保護機制，學習如何透過 CLI 批准陌生發送者的配對請求、列出待批准請求和管理允許清單。本教程完整介紹配對流程、CLI 指令使用、存取策略設定和安全最佳實踐，包含常見錯誤排除和 doctor 指令。","frontmatter":{"title":"DM 配對與存取控制：保護你的 AI 助手 | Clawdbot 教程","sidebarTitle":"管理陌生人存取","subtitle":"DM 配對與存取控制：保護你的 AI 助手","description":"了解 Clawdbot 的 DM 配對保護機制，學習如何透過 CLI 批准陌生發送者的配對請求、列出待批准請求和管理允許清單。本教程完整介紹配對流程、CLI 指令使用、存取策略設定和安全最佳實踐，包含常見錯誤排除和 doctor 指令。","tags":["入門","安全","配對","存取控制"],"prerequisite":["start-gateway-startup"],"order":50},"headers":[],"relativePath":"zh-tw/moltbot/moltbot/start/pairing-approval/index.md","filePath":"zh-tw/moltbot/moltbot/start/pairing-approval/index.md"}'),l={name:"zh-tw/moltbot/moltbot/start/pairing-approval/index.md"};function o(n,a,r,d,p,c){return s(),i("div",null,[...a[0]||(a[0]=[e(`<h1 id="dm-配對與存取控制-保護你的-ai-助手" tabindex="-1">DM 配對與存取控制：保護你的 AI 助手 <a class="header-anchor" href="#dm-配對與存取控制-保護你的-ai-助手" aria-label="Permalink to &quot;DM 配對與存取控制：保護你的 AI 助手&quot;">​</a></h1><h2 id="學完你能做什麼" tabindex="-1">學完你能做什麼 <a class="header-anchor" href="#學完你能做什麼" aria-label="Permalink to &quot;學完你能做什麼&quot;">​</a></h2><p>完成本教程後，你將能夠：</p><ul><li>✅ 理解預設的 DM 配對保護機制</li><li>✅ 批准陌生發送者的配對請求</li><li>✅ 列出和管理待批准的配對請求</li><li>✅ 設定不同的 DM 存取策略（pairing/allowlist/open）</li><li>✅ 執行 doctor 檢查安全設定</li></ul><h2 id="你現在的困境" tabindex="-1">你現在的困境 <a class="header-anchor" href="#你現在的困境" aria-label="Permalink to &quot;你現在的困境&quot;">​</a></h2><p>你可能剛設定了 WhatsApp 或 Telegram 頻道，希望與 AI 助手對話，但遇到了以下問題：</p><ul><li>&quot;為什麼陌生人給我發訊息，Clawdbot 不回覆？&quot;</li><li>&quot;收到一個配對代碼，不知道是什麼意思&quot;</li><li>&quot;想批准某個人的請求，但不知道用什麼指令&quot;</li><li>&quot;如何確認目前有哪些人在等待批准？&quot;</li></ul><p>好消息是：<strong>Clawdbot 預設啟用 DM 配對保護</strong>，這是為了確保只有你授權的發送者才能與 AI 助手對話。</p><h2 id="什麼時候用這一招" tabindex="-1">什麼時候用這一招 <a class="header-anchor" href="#什麼時候用這一招" aria-label="Permalink to &quot;什麼時候用這一招&quot;">​</a></h2><p>當你需要：</p><ul><li>🛡 <strong>保護隱私</strong>：確保只有信任的人能與 AI 助手對話</li><li>✅ <strong>批准陌生人</strong>：允許新的發送者存取你的 AI 助手</li><li>🔒 <strong>嚴格存取控制</strong>：限制特定使用者的存取權限</li><li>📋 <strong>批次管理</strong>：查看和管理所有待批准的配對請求</li></ul><hr><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><h3 id="什麼是-dm-配對" tabindex="-1">什麼是 DM 配對？ <a class="header-anchor" href="#什麼是-dm-配對" aria-label="Permalink to &quot;什麼是 DM 配對？&quot;">​</a></h3><p>Clawdbot 連接到真實的訊息平台（WhatsApp、Telegram、Slack 等），這些平台上的<strong>私聊（DM）預設被視為不受信任的輸入</strong>。</p><p>為了保護你的 AI 助手，Clawdbot 提供了<strong>配對機制</strong>：</p><div class="info custom-block"><p class="custom-block-title">配對流程</p><ol><li>陌生發送者向你發送訊息</li><li>Clawdbot 偵測到該發送者未被授權</li><li>Clawdbot 返回一個<strong>配對代碼</strong>（8 位字元）</li><li>發送者需要將配對代碼提供給你</li><li>你透過 CLI 批准該代碼</li><li>發送者 ID 被新增到允許清單</li><li>發送者可以正常與 AI 助手對話</li></ol></div><h3 id="預設-dm-策略" tabindex="-1">預設 DM 策略 <a class="header-anchor" href="#預設-dm-策略" aria-label="Permalink to &quot;預設 DM 策略&quot;">​</a></h3><p><strong>所有頻道預設使用 <code>dmPolicy=&quot;pairing&quot;</code></strong>，這表示：</p><table tabindex="0"><thead><tr><th>策略</th><th>行為</th></tr></thead><tbody><tr><td><code>pairing</code></td><td>未知發送者收到配對代碼，訊息不處理（預設）</td></tr><tr><td><code>allowlist</code></td><td>只允許 <code>allowFrom</code> 清單中的發送者</td></tr><tr><td><code>open</code></td><td>允許所有發送者（需顯式設定 <code>&quot;*&quot;</code>）</td></tr><tr><td><code>disabled</code></td><td>完全停用 DM 功能</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">安全提醒</p><p>預設的 <code>pairing</code> 模式是最安全的選擇。除非你有特殊需求，否則不要修改為 <code>open</code> 模式。</p></div><hr><h2 id="🎒-開始前的準備" tabindex="-1">🎒 開始前的準備 <a class="header-anchor" href="#🎒-開始前的準備" aria-label="Permalink to &quot;🎒 開始前的準備&quot;">​</a></h2><p>確保你已經：</p><ul><li>[x] 完成了 <a href="./../getting-started/">快速開始</a> 教程</li><li>[x] 完成了 <a href="./../gateway-startup/">啟動 Gateway</a> 教程</li><li>[x] 設定了至少一個訊息頻道（WhatsApp、Telegram、Slack 等）</li><li>[x] Gateway 正在執行</li></ul><hr><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to &quot;跟我做&quot;">​</a></h2><h3 id="第-1-步-理解配對代碼的來源" tabindex="-1">第 1 步：理解配對代碼的來源 <a class="header-anchor" href="#第-1-步-理解配對代碼的來源" aria-label="Permalink to &quot;第 1 步：理解配對代碼的來源&quot;">​</a></h3><p>當一個陌生發送者向你的 Clawdbot 發送訊息時，他們會收到類似以下的回覆：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Clawdbot: access not configured.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Telegram ID: 123456789</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Pairing code: AB3D7X9K</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Ask the bot owner to approve with:</span></span>
<span class="line"><span>clawdbot pairing approve telegram &lt;code&gt;</span></span></code></pre></div><p><strong>配對代碼的關鍵特性</strong>（來源：<code>src/pairing/pairing-store.ts</code>）：</p><ul><li><strong>8 位字元</strong>：便於輸入和記憶</li><li><strong>大寫字母和數字</strong>：避免混淆</li><li><strong>排除易混淆字元</strong>：不包含 0、O、1、I</li><li><strong>1 小時有效期</strong>：超過時間會自動失效</li><li><strong>最多保留 3 個待批准請求</strong>：超過後會自動清理最舊的請求</li></ul><h3 id="第-2-步-列出待批准的配對請求" tabindex="-1">第 2 步：列出待批准的配對請求 <a class="header-anchor" href="#第-2-步-列出待批准的配對請求" aria-label="Permalink to &quot;第 2 步：列出待批准的配對請求&quot;">​</a></h3><p>在終端機中執行以下指令：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">clawdbot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pairing</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> telegram</span></span></code></pre></div><p><strong>你應該看到</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Pairing requests (1)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>┌──────────────────┬────────────────┬────────┬──────────────────────┐</span></span>
<span class="line"><span>│ Code            │ ID            │ Meta   │ Requested            │</span></span>
<span class="line"><span>├──────────────────┼────────────────┼────────┼──────────────────────┤</span></span>
<span class="line"><span>│ AB3D7X9K        │ 123456789      │        │ 2026-01-27T10:30:00Z │</span></span>
<span class="line"><span>└──────────────────┴────────────────┴────────┴──────────────────────┘</span></span></code></pre></div><p>如果沒有待批准的請求，你會看到：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>No pending telegram pairing requests.</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">支援的頻道</p><p>配對功能支援以下頻道：</p><ul><li>telegram</li><li>whatsapp</li><li>slack</li><li>discord</li><li>signal</li><li>imessage</li><li>msteams</li><li>googlechat</li><li>bluebubbles</li></ul></div><h3 id="第-3-步-批准配對請求" tabindex="-1">第 3 步：批准配對請求 <a class="header-anchor" href="#第-3-步-批准配對請求" aria-label="Permalink to &quot;第 3 步：批准配對請求&quot;">​</a></h3><p>使用發送者提供的配對代碼批准存取：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">clawdbot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pairing</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> approve</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> telegram</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> AB3D7X9K</span></span></code></pre></div><p><strong>你應該看到</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✅ Approved telegram sender 123456789</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">批准後的效果</p><p>批准後，發送者 ID（123456789）會被自動新增到該頻道的允許清單中，儲存在： <code>~/.clawdbot/credentials/telegram-allowFrom.json</code></p></div><h3 id="第-4-步-通知發送者-可選" tabindex="-1">第 4 步：通知發送者（可選） <a class="header-anchor" href="#第-4-步-通知發送者-可選" aria-label="Permalink to &quot;第 4 步：通知發送者（可選）&quot;">​</a></h3><p>如果你想自動通知發送者，可以使用 <code>--notify</code> 標誌：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">clawdbot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pairing</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> approve</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> telegram</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> AB3D7X9K</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --notify</span></span></code></pre></div><p>發送者會收到以下訊息（來源：<code>src/channels/plugins/pairing-message.ts</code>）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✅ Clawdbot access approved. Send a message to start chatting.</span></span></code></pre></div><p><strong>注意</strong>：<code>--notify</code> 標誌要求 Clawdbot Gateway 正在執行，並且該頻道處於活躍狀態。</p><h3 id="第-5-步-驗證發送者可以正常對話" tabindex="-1">第 5 步：驗證發送者可以正常對話 <a class="header-anchor" href="#第-5-步-驗證發送者可以正常對話" aria-label="Permalink to &quot;第 5 步：驗證發送者可以正常對話&quot;">​</a></h3><p>讓發送者再次發送一條訊息，AI 助手應該會正常回覆。</p><hr><h2 id="檢查點-✅" tabindex="-1">檢查點 ✅ <a class="header-anchor" href="#檢查點-✅" aria-label="Permalink to &quot;檢查點 ✅&quot;">​</a></h2><p>完成以下檢查確認設定正確：</p><ul><li>[ ] 執行 <code>clawdbot pairing list &lt;channel&gt;</code> 能看到待批准的請求</li><li>[ ] 使用 <code>clawdbot pairing approve &lt;channel&gt; &lt;code&gt;</code> 能成功批准</li><li>[ ] 批准後的發送者能正常與 AI 助手對話</li><li>[ ] 配對代碼會在 1 小時後自動過期（可以透過再次發送訊息驗證）</li></ul><hr><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><h3 id="錯誤-1-找不到配對代碼" tabindex="-1">錯誤 1：找不到配對代碼 <a class="header-anchor" href="#錯誤-1-找不到配對代碼" aria-label="Permalink to &quot;錯誤 1：找不到配對代碼&quot;">​</a></h3><p><strong>錯誤訊息</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>No pending pairing request found for code: AB3D7X9K</span></span></code></pre></div><p><strong>可能原因</strong>：</p><ul><li>配對代碼已經過期（超過 1 小時）</li><li>配對代碼輸入錯誤（檢查大小寫）</li><li>發送者沒有實際發送訊息（配對代碼只有在收到訊息時才會產生）</li></ul><p><strong>解決方法</strong>：</p><ul><li>讓發送者再次發送一條訊息，產生新的配對代碼</li><li>確保配對代碼正確複製（注意大小寫）</li></ul><h3 id="錯誤-2-頻道不支援配對" tabindex="-1">錯誤 2：頻道不支援配對 <a class="header-anchor" href="#錯誤-2-頻道不支援配對" aria-label="Permalink to &quot;錯誤 2：頻道不支援配對&quot;">​</a></h3><p><strong>錯誤訊息</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Channel xxx does not support pairing</span></span></code></pre></div><p><strong>可能原因</strong>：</p><ul><li>頻道名稱拼字錯誤</li><li>該頻道不支援配對功能</li></ul><p><strong>解決方法</strong>：</p><ul><li>執行 <code>clawdbot pairing list</code> 查看支援的頻道清單</li><li>使用正確的頻道名稱</li></ul><h3 id="錯誤-3-通知失敗" tabindex="-1">錯誤 3：通知失敗 <a class="header-anchor" href="#錯誤-3-通知失敗" aria-label="Permalink to &quot;錯誤 3：通知失敗&quot;">​</a></h3><p><strong>錯誤訊息</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Failed to notify requester: &lt;error details&gt;</span></span></code></pre></div><p><strong>可能原因</strong>：</p><ul><li>Gateway 未執行</li><li>頻道連線斷開</li><li>網路問題</li></ul><p><strong>解決方法</strong>：</p><ul><li>確認 Gateway 正在執行</li><li>檢查頻道連線狀態：<code>clawdbot channels status</code></li><li>不使用 <code>--notify</code> 標誌，手動通知發送者</li></ul><hr><h2 id="本課小結" tabindex="-1">本課小結 <a class="header-anchor" href="#本課小結" aria-label="Permalink to &quot;本課小結&quot;">​</a></h2><p>本教程介紹了 Clawdbot 的 DM 配對保護機制：</p><ul><li><strong>預設安全</strong>：所有頻道預設使用 <code>pairing</code> 模式，保護你的 AI 助手</li><li><strong>配對流程</strong>：陌生發送者收到 8 位配對代碼，你需要透過 CLI 批准</li><li><strong>管理指令</strong>： <ul><li><code>clawdbot pairing list &lt;channel&gt;</code>：列出待批准請求</li><li><code>clawdbot pairing approve &lt;channel&gt; &lt;code&gt;</code>：批准配對</li></ul></li><li><strong>儲存位置</strong>：允許清單儲存在 <code>~/.clawdbot/credentials/&lt;channel&gt;-allowFrom.json</code></li><li><strong>自動過期</strong>：配對請求 1 小時後自動失效</li></ul><p>記住：<strong>配對機制是 Clawdbot 的安全基石</strong>，確保只有你授權的人能與 AI 助手對話。</p><hr><h2 id="下一課預告" tabindex="-1">下一課預告 <a class="header-anchor" href="#下一課預告" aria-label="Permalink to &quot;下一課預告&quot;">​</a></h2><blockquote><p>下一課我們將學習 <strong><a href="./../../faq/troubleshooting/">疑難排解：解決常見問題</a></strong>。</p><p>你會學到：</p><ul><li>快速診斷和系統狀態檢查</li><li>解決 Gateway 啟動、頻道連線、認證錯誤等問題</li><li>工具呼叫失敗和效能優化的排除方法</li></ul></blockquote><hr><h2 id="附錄-原始碼參考" tabindex="-1">附錄：原始碼參考 <a class="header-anchor" href="#附錄-原始碼參考" aria-label="Permalink to &quot;附錄：原始碼參考&quot;">​</a></h2><details><summary><strong>點擊展開查看原始碼位置</strong></summary><blockquote><p>更新時間：2026-01-27</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>檔案路徑</th><th>行號</th></tr></thead><tbody><tr><td>配對代碼產生（8 位，排除易混淆字元）</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/pairing/pairing-store.ts#L173-L181" target="_blank" rel="noreferrer"><code>src/pairing/pairing-store.ts</code></a></td><td>173-181</td></tr><tr><td>配對請求儲存與 TTL（1 小時）</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/pairing/pairing-store.ts#L11-L14" target="_blank" rel="noreferrer"><code>src/pairing/pairing-store.ts</code></a></td><td>11-14</td></tr><tr><td>批准配對指令</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/cli/pairing-cli.ts#L107-L143" target="_blank" rel="noreferrer"><code>src/cli/pairing-cli.ts</code></a></td><td>107-143</td></tr><tr><td>配對代碼訊息產生</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/pairing/pairing-messages.ts#L4-L20" target="_blank" rel="noreferrer"><code>src/pairing/pairing-messages.ts</code></a></td><td>4-20</td></tr><tr><td>允許清單儲存</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/pairing/pairing-store.ts#L457-L461" target="_blank" rel="noreferrer"><code>src/pairing/pairing-store.ts</code></a></td><td>457-461</td></tr><tr><td>支援 <code>pairing</code> 的頻道清單</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/channels/plugins/pairing.ts#L11-L16" target="_blank" rel="noreferrer"><code>src/channels/plugins/pairing.ts</code></a></td><td>11-16</td></tr><tr><td>預設 DM 策略（pairing）</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/config/zod-schema.providers-core.ts#L93" target="_blank" rel="noreferrer"><code>src/config/zod-schema.providers-core.ts</code></a></td><td>93</td></tr></tbody></table><p><strong>關鍵常數</strong>：</p><ul><li><code>PAIRING_CODE_LENGTH = 8</code>：配對代碼長度</li><li><code>PAIRING_CODE_ALPHABET = &quot;ABCDEFGHJKLMNPQRSTUVWXYZ23456789&quot;</code>：配對代碼字元集（排除 0O1I）</li><li><code>PAIRING_PENDING_TTL_MS = 60 * 60 * 1000</code>：配對請求有效期（1 小時）</li><li><code>PAIRING_PENDING_MAX = 3</code>：最大待批准請求數</li></ul><p><strong>關鍵函數</strong>：</p><ul><li><code>approveChannelPairingCode()</code>：批准配對代碼並新增到允許清單</li><li><code>listChannelPairingRequests()</code>：列出待批准的配對請求</li><li><code>upsertChannelPairingRequest()</code>：建立或更新配對請求</li><li><code>addChannelAllowFromStoreEntry()</code>：新增發送者到允許清單</li></ul></details>`,92)])])}const b=t(l,[["render",o]]);export{g as __pageData,b as default};
